    doc.addEventListener('dragover',event=>{const types=[...(event.dataTransfer?.types||[])];if(!types.includes('application/x-mannypay-icon')&&!types.includes('application/x-mannypay-element')&&!types.includes('application/x-mannypay-image'))return;const target=event.target.closest?.('[data-studio-id]');if(!target)return;event.preventDefault();event.dataTransfer.dropEffect='copy';doc.querySelectorAll('.studio-icon-drop-target').forEach(el=>el.classList.remove('studio-icon-drop-target'));target.classList.add('studio-icon-drop-target')},true);
