    doc.addEventListener('drop',event=>{const iconRaw=event.dataTransfer?.getData('application/x-mannypay-icon')||'',elementRaw=event.dataTransfer?.getData('application/x-mannypay-element')||'',componentRaw=event.dataTransfer?.getData('application/x-mannypay-component')||'',imageRaw=event.dataTransfer?.getData('application/x-mannypay-image')||'',target=event.target.closest?.('[data-studio-id]');if(!target)return;if(iconLibrary.includes(iconRaw)){event.preventDefault();event.stopPropagation();insertIcon(iconRaw,target)}else if(elementTemplates[elementRaw]){event.preventDefault();event.stopPropagation();addElement(elementRaw,target)}else if(componentTemplates[componentRaw]){event.preventDefault();event.stopPropagation();selectElement(target);addComponent(componentRaw)}else if(imageRaw){const asset=mediaAssets().find(item=>item.id===imageRaw);if(!asset)return;event.preventDefault();event.stopPropagation();useMedia(asset,target)}else return;doc.querySelectorAll('.studio-icon-drop-target').forEach(el=>el.classList.remove('studio-icon-drop-target'))},true);
